    """Convert numpy types to Python native types"""
    if isinstance(obj, np.ndarray):
        return obj.tolist()
    elif isinstance(obj, (np.int64, np.int32)):
        return int(obj)
    elif isinstance(obj, (np.float64, np.float32)):
        return float(obj)
    elif isinstance(obj, dict):
        return {k: convert_to_serializable(v) for k, v in obj.items()}
    elif isinstance(obj, list):
        return [convert_to_serializable(i) for i in obj]
    return obj

# Read parquet file
df = pd.read_parquet('context/validation-00000-of-00001.parquet')

# Convert to JSONL format
with open('validation.jsonl', 'w') as f:
    for idx, row in df.iterrows():
        record = {
            'id': row['id'],
            'question': row['question'],
            'question_concept': row['question_concept'],
            'choices': convert_to_serializable(row['choices']),
            'answerKey': row['answerKey']
        }
        f.write(json.dumps(record) + '\n')

print(f"Converted {len(df)} records to validation.jsonl")
